-- LEVITICUS CHAPTER 25 — God's Sovereignty: Rest, Redemption, and Restoration of Land and People
-- 55 verses · Original text · Word studies · Cross-refs
-- ═══════════════════════════════════════════════════════

-- Step 1: Insert chapter metadata
INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 25,
  'Leviticus 25 outlines the laws concerning the Sabbatical year (Shemitah) and the Year of Jubilee (Yovel). These divinely ordained economic and social systems were designed to prevent extreme wealth disparity, ensure land redistribution, and promote social justice within Israel. The Sabbatical year mandated rest for the land every seven years, allowing it to lie fallow and providing for the poor and animals. The Jubilee, occurring every fifty years, involved the return of all ancestral land to its original owners and the release of Israelite indentured servants. The chapter emphasizes God''s ownership of the land and His people, reminding them that they are ''strangers and sojourners'' with Him, thereby fostering dependence on divine provision and upholding the covenant relationship. These regulations served as a practical demonstration of Israel''s unique identity as God''s chosen nation, reflecting His character of justice, mercy, and sovereignty, and foreshadowing ultimate redemption and restoration.',
  'God''s Sovereignty: Rest, Redemption, and Restoration of Land and People',
  'יוֹבֵל (yovel)',
  'The Hebrew word יוֹבֵל (yovel) refers to the "Jubilee," derived from the root meaning "ram''s horn" or "trumpet," which was blown to announce the year. Theologically, it signifies a year of ultimate liberation and restoration, where land returns to its original families and Israelite slaves are freed. It underscores God''s ownership of all things and His provision for justice and equity among His people, preventing permanent disenfranchisement and reminding Israel of their status as His tenants.',
  '["Section 1 (vv.1-7): The Law of the Sabbatical Year (Shemitah)","Section 2 (vv.8-17): The Law of the Year of Jubilee (Yovel)","Section 3 (vv.18-22): Divine Provision and Assurance for Obedience","Section 4 (vv.23-34): Laws Concerning the Redemption of Land and Houses","Section 5 (vv.35-38): Laws Concerning Loans and Usury to the Poor","Section 6 (vv.39-46): Laws Concerning Israelite and Foreign Servitude","Section 7 (vv.47-55): Redemption of an Israelite Sold to a Foreigner"]'
FROM books b WHERE b.name = 'Leviticus';

-- Step 2: Insert all 55 verses
INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1,
   'And the LORD spake unto Moses in mount Sinai, saying,',
   'וַיְדַבֵּר יְהוָה אֶל־מֹשֶׁה בְּהַר סִינַי לֵאמֹר׃',
   'Vaydabēr YHWH el-Mosheh bəhar Sinai lēʼmōr.',
   'This verse sets the stage for the entire chapter, indicating that the laws of the Sabbatical and Jubilee years were given directly by the LORD to Moses on Mount Sinai. This divine origin underscores their authority and importance, placing them within the foundational covenant instructions for Israel''s life in the promised land. The phrase "in Mount Sinai" connects these specific social and economic regulations to the broader Mosaic covenant, emphasizing that Israel''s prosperity and well-being were contingent upon their obedience to God''s commands (Exod 19:1-6).',
   NULL),
  (2,
   'Speak unto the children of Israel, and say unto them, When ye come into the land which I give you, then shall the land keep a sabbath unto the LORD.',
   'דַּבֵּר אֶל־בְּנֵי יִשְׂרָאֵל וְאָמַרְתָּ אֲלֵהֶם כִּי תָבֹאוּ אֶל־הָאָרֶץ אֲשֶׁר אֲנִי נֹתֵן לָכֶם וְשָׁבְתָה הָאָרֶץ שַׁבָּת לַיהוָה׃',
   'Dabēr el-bənê Yiśrāʼēl vāʼāmartā ʼalêhem kî tāvōʼū el-hāʼāreṣ ʼăšer ʼănî nōtēn lākem vəšāvtāh hāʼāreṣ šabbat laYHWH.',
   'The command is directed to "the children of Israel" and applies specifically "when ye come into the land which I give you." This highlights the conditional nature of their possession of the land, which is a divine gift. The concept of the land keeping a "sabbath unto the LORD" introduces the idea that even the physical earth has a sacred rhythm and purpose, mirroring the weekly Sabbath for humans. It emphasizes God''s ultimate ownership and the land''s sacred character (Lev 25:23).',
   'This verse establishes the theological principle of God''s sovereignty over the land. The land is not merely a possession but a sacred trust, requiring regular rest and acknowledgment of its divine owner. This concept extends to all creation, reminding humanity of its stewardship rather than absolute ownership, and foreshadows the eschatological rest and renewal of all things (Rom 8:19-22).'),
  (3,
   'Six years thou shalt sow thy field, and six years thou shalt prune thy vineyard, and gather in the fruit thereof;',
   'שֵׁשׁ שָׁנִים תִּזְרַע שָׂדֶךָ וְשֵׁשׁ שָׁנִים תִּזְמֹר כַּרְמֶךָ וְאָסַפְתָּ אֶת־תְּבוּאָתָהּ׃',
   'Shēš shānîm tizraʿ śādeḵā v''shēš shānîm tizmor karmekā v''āsaftā et-təvûʼātāh.',
   'This verse details the agricultural activities permitted during the six working years preceding the Sabbatical year. "Sow thy field" (תִּזְרַע שָׂדֶךָ) and "prune thy vineyard" (תִּזְמֹר כַּרְמֶךָ) represent the primary agricultural labors. The instruction to "gather in the fruit thereof" (וְאָסַפְתָּ אֶת־תְּבוּאָתָהּ) indicates normal harvesting practices. This period of labor is set in contrast to the mandated rest of the seventh year, establishing a rhythm of work and rest (Exod 23:10-11).',
   NULL),
  (4,
   'But in the seventh year shall be a sabbath of rest unto the land, a sabbath for the LORD: thou shalt neither sow thy field, nor prune thy vineyard.',
   'וּבַשָּׁנָה הַשְּׁבִיעִת שַׁבַּת שַׁבָּתוֹן יִהְיֶה לָאָרֶץ שַׁבָּת לַיהוָה שָׂדְךָ לֹא תִזְרָע וְכַרְמְךָ לֹא תִזְמֹר׃',
   'Uvaššānāh haššəvîʿît šabbat shabbātôn yihyeh lāʼāreṣ šabbat laYHWH śādeḵā lōʼ tizrāʿ v''karməḵā lōʼ tizmor.',
   'The seventh year is designated a "sabbath of rest unto the land" (שַׁבַּת שַׁבָּתוֹן יִהְיֶה לָאָרֶץ), a phrase emphasizing its sacred and complete cessation of agricultural work. The double use of "sabbath" (שַׁבַּת שַׁבָּתוֹן) intensifies the command, indicating a holy rest. This prohibition against sowing and pruning underscores the land''s need for rejuvenation and Israel''s reliance on God''s provision rather than their own continuous labor (Exod 23:11).',
   'The Sabbatical year for the land reflects the divine pattern of rest established at creation (Gen 2:2-3). It teaches trust in God''s provision, demonstrating that true security comes from obedience to His commands, not from human toil alone. This principle of rest and reliance on God is a recurring theme in Scripture, pointing to the ultimate rest found in Christ (Heb 4:9-10).'),
  (5,
   'That which groweth of its own accord of thy harvest thou shalt not reap, neither gather the grapes of thy vine undressed: for it is a year of rest unto the land.',
   'אֵת סְפִיחַ קְצִירְךָ לֹא תִקְצוֹר וְאֶת־עִנְּבֵי נְזִירֶךָ לֹא תִבְצֹר שְׁנַת שַׁבָּתוֹן יִהְיֶה לָאָרֶץ׃',
   'ʾĒt səpîaḥ qəṣîrḵā lōʾ tiqṣôr wəʾet-ʿinnəvē nəzîreḵā lōʾ tivṣōr šənat shabbātôn yihyeh lāʾāreṣ.',
   'This verse further clarifies the restrictions of the Sabbatical year, prohibiting the reaping of "that which groweth of its own accord" (סְפִיחַ קְצִירְךָ) and the gathering of grapes from "thy vine undressed" (עִנְּבֵי נְזִירֶךָ). These spontaneous growths were not to be harvested for personal profit, but left for the poor, the stranger, and animals (Lev 25:6-7). This demonstrates a principle of generosity and communal sharing, ensuring that even in a year of rest, provision was made for all.',
   NULL),
  (6,
   'And the sabbath of the land shall be meat for you; for thee, and for thy servant, and for thy maid, and for thy hired servant, and for thy stranger that sojourneth with thee,',
   'וְהָיְתָה שַׁבַּת הָאָרֶץ לָכֶם לְאָכְלָה לְךָ וּלְעַבְדְּךָ וְלַאֲמָתֶךָ וְלִשְׂכִירְךָ וּלְתוֹשָׁבְךָ הַגָּר עִמָּךְ׃',
   'Vəhāyətāh shabbat hāʼāreṣ lāḵem ləʼoḵlāh ləḵā uləʿavdəḵā vlaʼămāteḵā vliśḵîrḵā ulətôšāvḵā haggār ʿimmāḵ.',
   'The produce of the Sabbatical year, though not to be formally harvested, was designated as "meat" (לְאָכְלָה, food) for everyone: the landowner, servants, hired workers, and resident strangers. This provision highlights the communal and equitable nature of the Sabbatical year. It ensured that the cessation of work did not lead to starvation but rather fostered a shared dependence on God''s natural bounty, promoting social solidarity and care for the vulnerable (Deut 15:7-11).',
   'This command illustrates God''s concern for social justice and the welfare of all, especially the marginalized. The Sabbatical year''s provision for servants, hired workers, and strangers demonstrates a divine economy where resources are shared, reflecting God''s character as a provider for all His creation. It challenges self-centered accumulation and promotes a communal ethos (Acts 2:44-45).'),
  (7,
   'And for thy cattle, and for the beast that are in thy land, shall all the increase thereof be meat.',
   'וְלִבְהֶמְתְּךָ וְלַחַיָּה אֲשֶׁר בְּאַרְצֶךָ תִּהְיֶה כָל־תְּבוּאָתָהּ לְאָכְלָה׃',
   'Vəlivhemtəḵā vlaḥayyāh ʼăšer bəʼarṣeḵā tihyeh kol-təvûʼātāh ləʼoḵlāh.',
   'Extending the principle of communal provision, this verse includes "thy cattle, and for the beast that are in thy land" as beneficiaries of the land''s spontaneous produce during the Sabbatical year. This demonstrates a holistic view of creation, where even animals are included in the divine provision and rest. It underscores the interconnectedness of all life and God''s care for the entire ecosystem, not just humanity (Ps 104:27-28).',
   NULL),
  (8,
   'And thou shalt number seven sabbaths of years unto thee, seven times seven years; and the space of the seven sabbaths of years shall be unto thee forty and nine years.',
   'וְסָפַרְתָּ לְךָ שֶׁבַע שַׁבְּתֹת שָׁנִים שֶׁבַע שָׁנִים שֶׁבַע פְּעָמִים וְהָיוּ לְךָ יְמֵי שֶׁבַע שַׁבְּתֹת הַשָּׁנִים אַרְבָּעִים וָתֵשַׁע שָׁנָה׃',
   'Vəṣāpartā ləḵā shevaʿ shabbətôt shānîm shevaʿ shānîm shevaʿ pəʿāmîm v''hāyû ləḵā yəmê shevaʿ shabbətôt haššānîm arbaʿîm vātēshaʿ shānāh.',
   'This verse introduces the calculation for the Year of Jubilee. Israel was to count "seven sabbaths of years," meaning seven cycles of seven years, totaling forty-nine years. This meticulous counting emphasizes the divine order and precision in God''s calendar. The number seven, signifying completeness and perfection, is central to both the Sabbatical and Jubilee cycles, highlighting their sacred significance (Gen 2:2-3; Exod 20:8-11).',
   'The emphasis on the number seven and its multiples (49 years) points to God''s perfect ordering of time and His plan for cyclical renewal. This divine rhythm is not arbitrary but reflects God''s character, establishing patterns of rest, release, and restoration that ultimately find their fulfillment in the eschatological kingdom and the eternal Sabbath (Rev 21:1-4).'),
  (9,
   'Then shalt thou cause the trumpet of the jubile to sound on the tenth day of the seventh month, in the day of atonement shall ye make the trumpet sound throughout all your land.',
   'וְהַעֲבַרְתָּ שׁוֹפַר תְּרוּעָה בַּחֹדֶשׁ הַשְּׁבִעִי בֶּעָשׂוֹר לַחֹדֶשׁ בְּיוֹם הַכִּפֻּרִים תַּעֲבִירוּ שׁוֹפָר בְּכָל־אַרְצְכֶם׃',
   'Vəhaʿăvartā shôfar tərûʿāh baḥōdeš haššəvîʿî beʿāśôr laḥōdeš bəyôm hakkippurîm taʿăvîrû shôfar bəḵol-ʾarṣəḵem.',
   'The Jubilee year was to be proclaimed on the "tenth day of the seventh month," which was Yom Kippur, the Day of Atonement. The sounding of the "trumpet of the jubile" (שׁוֹפַר תְּרוּעָה) throughout the land marked this momentous occasion. The connection to Yom Kippur is significant, linking the spiritual atonement for sins with social and economic liberation, suggesting that true reconciliation with God should lead to justice and freedom among people (Lev 16:29-34).',
   'The timing of the Jubilee on Yom Kippur is highly symbolic. It links spiritual cleansing and reconciliation with God to tangible social and economic liberation. This demonstrates that true atonement should manifest in acts of justice, mercy, and restoration within the community, foreshadowing Christ''s work of spiritual and ultimate liberation (Luke 4:18-19; Isa 61:1-2).'),
  (10,
   'And ye shall hallow the fiftieth year, and proclaim liberty throughout all the land unto all the inhabitants thereof: it shall be a jubile unto you; and ye shall return every man unto his possession, and ye shall return every man unto his family.',
   'וְקִדַּשְׁתֶּם אֵת שְׁנַת הַחֲמִשִּׁים שָׁנָה וּקְרָאתֶם דְּרוֹר בָּאָרֶץ לְכָל־יֹשְׁבֶיהָ יוֹבֵל הִוא תִּהְיֶה לָכֶם וְשַׁבְתֶּם אִישׁ אֶל־אֲחֻזָּתוֹ וְאִישׁ אֶל־מִשְׁפַּחְתּוֹ תָּשֻׁבוּ׃',
   'Vəqiddashtem ʾēt shənat haḥămiššîm shānāh ûqərāʾtem dərôr bāʾāreṣ ləḵol-yōšəveyhā yôvêl hîʾ tihyeh lāḵem v''šavtem ʾîš el-ʾăḥuzzātô v''ʾîš el-mišpaḥtô tāšuvû.',
   'This is the central declaration of the Jubilee. The fiftieth year is to be "hallowed" (וְקִדַּשְׁתֶּם) and "liberty" (דְּרוֹר) proclaimed to all inhabitants. The key outcomes are the return of every man "unto his possession" (אֶל־אֲחֻזָּתוֹ) and "unto his family" (אֶל־מִשְׁפַּחְתּוֹ). This radical redistribution and release prevented permanent poverty and ensured the preservation of tribal land inheritances, reflecting God''s design for equity and family stability (Num 36:7-9).',
   'The Jubilee''s proclamation of "liberty" (דְּרוֹר) and restoration of land and family is a profound theological statement. It underscores God''s commitment to justice, equity, and the preservation of human dignity. This concept of liberation and return foreshadows the ultimate redemption offered through Christ, who proclaims true freedom from sin and spiritual bondage (Isa 61:1-2; Luke 4:18-19).'),
  (11,
   'A jubile shall that fiftieth year be unto you: ye shall not sow, neither reap that which groweth of itself in it, nor gather the grapes in it of thy vine undressed.',
   'יוֹבֵל הִוא שְׁנַת הַחֲמִשִּׁים שָׁנָה תִּהְיֶה לָכֶם לֹא תִזְרָעוּ וְלֹא תִקְצְרוּ אֶת־סְפִיחֶיהָ וְלֹא תִבְצְרוּ אֶת־נְזִירֶיהָ׃',
   'Yôvêl hîʾ shənat haḥămiššîm shānāh tihyeh lāḵem lōʾ tizraʿû v''lōʾ tiqṣərû et-səpîḥeyhā v''lōʾ tivṣərû et-nəzîreyhā.',
   'Similar to the Sabbatical year, the Jubilee year also mandated a cessation of agricultural labor. "Ye shall not sow, neither reap that which groweth of itself... nor gather the grapes in it of thy vine undressed." This reinforces the principle of divine provision and rest, emphasizing that the land''s produce during this special year was a gift from God, to be shared communally, rather than a result of human effort (Lev 25:5).',
   NULL),
  (12,
   'For it is the jubile; it shall be holy unto you: ye shall eat the increase thereof out of the field.',
   'כִּי יוֹבֵל הִוא קֹדֶשׁ תִּהְיֶה לָכֶם מִן־הַשָּׂדֶה תֹּאכְלוּ אֶת־תְּבוּאָתָהּ׃',
   'Kî yôvêl hîʾ qōdeš tihyeh lāḵem min-haśśādeh tōʾḵəlû et-təvûʾātāh.',
   'The Jubilee year is declared "holy unto you" (קֹדֶשׁ תִּהְיֶה לָכֶם), signifying its sacred status and divine purpose. The instruction to "eat the increase thereof out of the field" (מִן־הַשָּׂדֶה תֹּאכְלוּ אֶת־תְּבוּאָתָהּ) implies a communal gathering of naturally growing produce, reinforcing the idea of shared sustenance and reliance on God''s spontaneous bounty, rather than individual cultivation and ownership (Exod 16:4-5).',
   'The holiness of the Jubilee year underscores that God''s economic and social laws are not merely practical but sacred, reflecting His character. Eating directly from the field symbolizes a return to a more primal, trusting relationship with God as the ultimate provider, free from the anxieties of human labor and accumulation. This points to a future where God''s provision is abundant and freely accessible (Matt 6:25-34).'),
  (13,
   'In the year of this jubile ye shall return every man unto his possession.',
   'בִּשְׁנַת הַיּוֹבֵל הַזֹּאת תָּשֻׁבוּ אִישׁ אֶל־אֲחֻזָּתוֹ׃',
   'Bišnat hayyôvêl hazzōʾt tāšuvû ʾîš el-ʾăḥuzzātô.',
   'This verse reiterates the core principle of the Jubilee: "In the year of this jubile ye shall return every man unto his possession." This restoration of ancestral land was crucial for maintaining the tribal and family inheritances established during the division of Canaan. It prevented the permanent alienation of land, ensuring that no family would be perpetually dispossessed and maintaining the social structure of Israel (Num 36:7).',
   NULL),
  (14,
   'And if thou sell ought unto thy neighbour, or buyest ought of thy neighbour’s hand, ye shall not oppress one another:',
   'וְכִי־תִמְכְּרוּ מִמְכָּר לַעֲמִיתֶךָ אוֹ קָנֹה מִיַּד עֲמִיתֶךָ אַל־תּוֹנוּ אִישׁ אֶת־אָחִיו׃',
   'Vəḵî-timkərû mimkār laʿămîteḵā ʾô qānōh miyyad ʿămîteḵā ʾal-tônû ʾîš et-ʾāḥîv.',
   'This verse introduces the ethical principle governing land transactions: "ye shall not oppress one another" (אַל־תּוֹנוּ אִישׁ אֶת־אָחִיו). The Hebrew verb תונו (tonu) means to "deal treacherously" or "defraud." Given the Jubilee''s land redistribution, any sale was effectively a lease until the Jubilee. Therefore, the price of land was to be determined by the number of years remaining until the next Jubilee, not by its intrinsic value, to prevent exploitation (Lev 25:15-16).',
   'This command against oppression in economic dealings highlights God''s demand for integrity and fairness in human relationships. It reflects the divine character of justice and mercy, emphasizing that business transactions among God''s people should be governed by ethical principles rather than pure self-interest. This principle is foundational to Christian ethics in commerce (Mic 6:8; 1 Thess 4:6).'),
  (15,
   'According to the number of years after the jubile thou shalt buy of thy neighbour, and according unto the number of years of the fruits he shall sell unto thee:',
   'בְּמִסְפַּר שָׁנִים אַחַר הַיּוֹבֵל תִּקְנֶה מֵאֵת עֲמִיתֶךָ וּבְמִסְפַּר שְׁנֵי תְבוּאֹת יִמְכָּר־לָךְ׃',
   'Bəmispar shānîm ʾaḥar hayyôvêl tiqneh mêʾēt ʿămîteḵā uvəmispar shənê təvûʾōt yimkār-lāḵ.',
   'This verse specifies how land prices were to be calculated. The buyer was to pay "according to the number of years after the jubile" (בְּמִסְפַּר שָׁנִים אַחַר הַיּוֹבֵל), and the seller was to sell "according unto the number of years of the fruits" (וּבְמִסְפַּר שְׁנֵי תְבוּאֹת). This means the transaction was essentially a lease for the remaining harvests until the Jubilee, not a permanent sale of the land itself. This system ensured fairness and upheld the ultimate principle of land reversion (Lev 25:23).',
   NULL),
  (16,
   'According to the multitude of years thou shalt increase the price thereof, and according to the fewness of years thou shalt diminish the price of it: for according to the number of the years of the fruits doth he sell unto thee.',
   'עַל־פִּי רֹב הַשָּׁנִים תַּרְבֶּה מִקְנָתוֹ וְעַל־פִּי מְעוּט הַשָּׁנִים תַּמְעִיט מִקְנָתוֹ כִּי מִסְפַּר תְּבוּאֹת הוּא מֹכֵר לָךְ׃',
   'ʿAl-pî rov haššānîm tarbeh miqnātô vʿal-pî məʿûṭ haššānîm tamʿîṭ miqnātô kî mispar təvûʾōt hûʾ môḵēr lāḵ.',
   'This verse elaborates on the pricing mechanism: "According to the multitude of years thou shalt increase the price thereof, and according to the fewness of years thou shalt diminish the price of it." The underlying principle is reiterated: "for according to the number of the years of the fruits doth he sell unto thee." This economic model is unique, reflecting a theological understanding of land ownership where God is the ultimate proprietor, and humans are temporary stewards (Lev 25:23).',
   NULL),
  (17,
   'Ye shall not therefore oppress one another; but thou shalt fear thy God:for I am the LORD your God.',
   'וְלֹא תוֹנוּ אִישׁ אֶת־עֲמִיתוֹ וְיָרֵאתָ מֵאֱלֹהֶיךָ כִּי אֲנִי יְהוָה אֱלֹהֵיכֶם׃',
   'Vəlōʾ tônû ʾîš et-ʿămîtô v''yārēʾtā mêʾĕlōheyḵā kî ʾănî YHWH ʾĕlōhêkem.',
   'This verse repeats the prohibition against oppression (וְלֹא תוֹנוּ אִישׁ אֶת־עֲמִיתוֹ) but adds a crucial motivation: "but thou shalt fear thy God: for I am the LORD your God." The fear of God is presented as the ultimate deterrent against exploitation, reminding Israel that their economic practices are not merely legal matters but expressions of their covenant relationship with a holy God. This divine imperative elevates ethical conduct to a spiritual plane (Deut 6:24; Prov 1:7).',
   'The command to "fear thy God" as the basis for ethical economic behavior is a cornerstone of biblical morality. It teaches that true reverence for God manifests in just and compassionate treatment of others, especially in financial dealings. This fear is not terror but a profound respect for God''s authority and character, recognizing Him as the ultimate judge and provider (Prov 9:10; 1 Pet 2:17).'),
  (18,
   'Wherefore ye shall do my statutes, and keep my judgments, and do them; and ye shall dwell in the land in safety.',
   'וַעֲשִׂיתֶם אֶת־חֻקֹּתַי וְאֶת־מִשְׁפָּטַי תִּשְׁמְרוּ וַעֲשִׂיתֶם אֹתָם וִישַׁבְתֶּם עַל־הָאָרֶץ לָבֶטַח׃',
   'Vaʿăśîtem et-ḥuqqōtay v''et-mišpāṭay tishmərû vaʿăśîtem ʾōtām vîšavtem ʿal-hāʾāreṣ lāveṭaḥ.',
   'This verse connects obedience to God''s "statutes" (חֻקֹּתַי) and "judgments" (מִשְׁפָּטַי) with the promise of dwelling "in the land in safety" (לָבֶטַח). This is a recurring theme in the Pentateuch, where covenant faithfulness leads to security and prosperity in the promised land. The Sabbatical and Jubilee laws, though seemingly challenging, are presented as the path to true stability and well-being for the nation (Deut 28:1-14).',
   'The promise of dwelling "in safety" (לָבֶטַח) upon obedience to God''s statutes and judgments highlights the direct correlation between covenant faithfulness and divine blessing. This theological principle, central to the Deuteronomic covenant, teaches that true security and prosperity for God''s people are found in submission to His righteous rule, not in human strength or wisdom (Deut 28:1-14; Ps 1:1-3).'),
  (19,
   'And the land shall yield her fruit, and ye shall eat your fill, and dwell therein in safety.',
   'וְנָתְנָה הָאָרֶץ יְבוּלָהּ וַאֲכַלְתֶּם לָשֹׂבַע וִישַׁבְתֶּם לָבֶטַח עָלֶיהָ׃',
   'Vənatnāh hāʾāreṣ yəvûlāh vaʾăḵaltem lāśōvaʿ vîšavtem lāveṭaḥ ʿāleyhā.',
   'This verse further elaborates on the blessings of obedience, promising that "the land shall yield her fruit" (וְנָתְנָה הָאָרֶץ יְבוּלָהּ) and Israel would "eat your fill" (וַאֲכַלְתֶּם לָשֹׂבַע) and "dwell therein in safety" (וִישַׁבְתֶּם לָבֶטַח עָלֶיהָ). This divine assurance directly addresses the practical concerns about food supply during the Sabbatical and Jubilee years, reinforcing the idea that God''s commands are for Israel''s good (Deut 11:13-15).',
   NULL),
  (20,
   'And if ye shall say, What shall we eat the seventh year? behold, we shall not sow, nor gather in our increase:',
   'וְכִי תֹאמְרוּ מַה־נֹּאכַל בַּשָּׁנָה הַשְּׁבִיעִת הֵן לֹא נִזְרָע וְלֹא נֶאֱסֹף אֶת־תְּבוּאָתֵנוּ׃',
   'Vəḵî tōʾmrû mah-nōʾḵal baššānāh haššəvîʿît hēn lōʾ nizraʿ v''lōʾ neʾĕsōf et-təvûʾātēnû.',
   'This verse anticipates the natural human question and anxiety regarding the Sabbatical year: "What shall we eat the seventh year? behold, we shall not sow, nor gather in our increase." This rhetorical question acknowledges the practical challenges and potential fear associated with suspending agricultural labor, setting the stage for God''s explicit promise of supernatural provision (Matt 6:31-32).',
   NULL),
  (21,
   'Then I will command my blessing upon you in the sixth year, and it shall bring forth fruit for three years.',
   'וְצִוִּיתִי אֶת־בִּרְכָתִי לָכֶם בַּשָּׁנָה הַשִּׁשִּׁית וְעָשָׂת אֶת־הַתְּבוּאָה לִשְׁלֹשׁ הַשָּׁנִים׃',
   'Vəṣivvîtî et-birḵātî lāḵem baššānāh haššiššît v''ʿāśāt et-hattəvûʾāh lišlōš haššānîm.',
   'In response to Israel''s anticipated concern, God promises, "Then I will command my blessing upon you in the sixth year, and it shall bring forth fruit for three years." This miraculous provision would cover the sixth year''s harvest, the entire seventh Sabbatical year, and the eighth year until its new harvest. This demonstrates God''s faithfulness and His ability to supernaturally sustain His people when they obey His commands (Exod 16:29; Mal 3:10).',
   'This promise of supernatural provision in the sixth year for three years'' worth of harvest is a powerful testament to God''s faithfulness and His ability to transcend natural limitations. It teaches radical dependence on God, assuring believers that obedience to His commands, even when seemingly counter-intuitive, will always be met with divine blessing and sustenance (Phil 4:19; Matt 6:33).'),
  (22,
   'And ye shall sow the eighth year, and eat yet of old fruit until the ninth year; until her fruits come in ye shall eat of the old store.',
   'וּזְרַעְתֶּם אֵת הַשָּׁנָה הַשְּׁמִינִת וַאֲכַלְתֶּם מִן־הַתְּבוּאָה יָשָׁן עַד הַשָּׁנָה הַתְּשִׁעִית עַד־בּוֹא תְבוּאָתָהּ תֹּאכְלוּ יָשָׁן׃',
   'Uzraʿtem ʾēt haššānāh haššəmînît vaʾăḵaltem min-hattəvûʾāh yāšān ʿad haššānāh hattəšiʿît ʿad-bôʾ təvûʾātāh tōʾḵəlû yāšān.',
   'This verse clarifies the duration of the miraculous provision. Israel would "sow the eighth year" but would continue to "eat yet of old fruit until the ninth year; until her fruits come in ye shall eat of the old store." This confirms that the blessing in the sixth year was sufficient to bridge the gap until the harvest of the eighth year became available, demonstrating God''s meticulous care for His people''s needs (Deut 28:12).',
   NULL),
  (23,
   'The land shall not be sold for ever: for the land is mine; for ye are strangers and sojourners with me.',
   'וְהָאָרֶץ לֹא תִמָּכֵר לִצְמִתֻת כִּי־לִי הָאָרֶץ כִּי־גֵרִים וְתוֹשָׁבִים אַתֶּם עִמָּדִי׃',
   'Vəhāʾāreṣ lōʾ timmāḵēr liṣmitut kî-lî hāʾāreṣ kî-gērîm v''tôshāvîm attem ʿimmādî.',
   'This is a foundational theological statement: "The land shall not be sold for ever: for the land is mine; for ye are strangers and sojourners with me." This declaration establishes God''s ultimate ownership of the land of Israel. Human ownership is temporary, akin to being "strangers and sojourners" (גֵּרִים וְתוֹשָׁבִים), emphasizing their dependent status and God''s sovereign rights. This principle undergirds the entire Jubilee system of land reversion (Ps 24:1; 1 Chr 29:15).',
   'This verse articulates the profound theological truth that God is the ultimate owner of all creation, particularly the promised land. Israel''s status as "strangers and sojourners" (גֵּרִים וְתוֹשָׁבִים) with God reminds them of their temporary earthly tenure and their eternal citizenship in His kingdom. This concept is echoed in the New Testament, where believers are called "strangers and pilgrims" on earth, awaiting a heavenly city (Heb 11:13-16; 1 Pet 2:11).'),
  (24,
   'And in all the land of your possession ye shall grant a redemption for the land.',
   'וּבְכֹל אֶרֶץ אֲחֻזַּתְכֶם גְּאֻלָּה תִּתְּנוּ לָאָרֶץ׃',
   'Uvəḵol ʾereṣ ʾăḥuzzatkem gəʾullāh tittənû lāʾāreṣ.',
   'Following the declaration of God''s ownership, this verse mandates that "in all the land of your possession ye shall grant a redemption for the land." The term "redemption" (גְּאֻלָּה, ge''ullah) here refers to the right or obligation to buy back alienated land. This law ensured that even if land was sold due to poverty, there was always a mechanism for its return before the Jubilee, reinforcing the principle of maintaining family inheritances (Ruth 4:4-6).',
   'The mandate for "redemption for the land" (גְּאֻלָּה תִּתְּנוּ לָאָרֶץ) underscores the temporary nature of human land ownership and the ultimate sovereignty of God. This legal provision ensured that ancestral inheritances, vital for tribal identity and stability, could be recovered, reflecting God''s design for order and justice within His covenant community (Num 36:7; Isa 5:8).'),
  (25,
   'If thy brother be waxen poor, and hath sold away some of his possession, and if any of his kin come to redeem it, then shall he redeem that which his brother sold.',
   'כִּי־יָמוּךְ אָחִיךָ וּמָכַר מֵאֲחֻזָּתוֹ וּבָא גֹאֲלוֹ הַקָּרֹב אֵלָיו וְגָאַל אֵת מִמְכַּר אָחִיו׃',
   'Kî-yāmûḵ ʾāḥîḵā ûmāḵar mêʾăḥuzzātô ûvāʾ gōʾălô haqqārōv ʾēlāyw v''gāʾal ʾēt mimkar ʾāḥîv.',
   'This verse outlines the process of land redemption by a kinsman-redeemer. If a brother "be waxen poor, and hath sold away some of his possession," then a "kinsman" (גֹאֲלוֹ הַקָּרֹב, go''alo haqqarov) has the right and duty to "redeem" (וְגָאַל, v''ga''al) it. This practice, known as the law of the "goel," provided a social safety net, preventing permanent loss of family land and protecting the impoverished (Ruth 2:20; Jer 32:7-8).',
   'The concept of the "kinsman-redeemer" (goel) is profoundly significant, foreshadowing Christ''s redemptive work. Just as the goel had to be a relative and possess the means to redeem, so Christ, through His incarnation, became our kinsman and, through His sacrifice, paid the price for our redemption from sin and spiritual poverty (Gal 4:4-5; Eph 1:7).'),
  (26,
   'And if the man have none to redeem it, and himself be able to redeem it;',
   'וְאִישׁ כִּי לֹא יִהְיֶה־לּוֹ גֹּאֵל וְהִשִּׂיגָה יָדוֹ וּמָצָא כְּדֵי גְאֻלָּתוֹ׃',
   'Vəʾîš kî lōʾ yihyeh-llô gōʾēl v''hissîgāh yādô ûmāṣāʾ kədê gəʾullātô.',
   'If there is no kinsman-redeemer, the impoverished individual himself could redeem his land if he "be able to redeem it" (וְהִשִּׂיגָה יָדוֹ וּמָצָא כְּדֵי גְאֻלָּתוֹ). This provision offered a path to self-redemption, allowing a person to recover their inheritance if their financial situation improved. It underscores the importance of land ownership for family identity and economic stability in Israelite society (Lev 27:27).',
   NULL),
  (27,
   'Then let him count the years of the sale thereof, and restore the overplus unto the man to whom he sold it; that he may return unto his possession.',
   'וְחִשַּׁב אֶת־שְׁנֵי מִמְכָּרוֹ וְהֵשִׁיב אֶת־הָעֹדֵף לָאִישׁ אֲשֶׁר מָכַר־לוֹ וְשָׁב לַאֲחֻזָּתוֹ׃',
   'Vəḥiššav et-shənê mimkārô v''hēšîv et-hāʿōdēf lāʾîš ʾăšer māḵar-lô v''shāv laʾăḥuzzātô.',
   'The redemption process involved calculating the remaining years until the Jubilee. The redeemer would "count the years of the sale thereof, and restore the overplus unto the man to whom he sold it." This means the original seller would refund the portion of the purchase price that corresponded to the years remaining on the "lease." This ensured fairness and allowed the land to return to its original owner (Lev 25:15-16).',
   NULL),
  (28,
   'But if he be not able to restore it to him, then that which is sold shall remain in the hand of him that hath bought it until the year of jubile: and in the jubile it shall go out, and he shall return unto his possession.',
   'וְאִם לֹא־מָצְאָה יָדוֹ דֵּי הָשִׁיב לוֹ וְהָיָה מִמְכָּרוֹ בְּיַד הַקֹּנֶה עַד שְׁנַת הַיּוֹבֵל וְיָצָא בַּיֹּבֵל וְשָׁב לַאֲחֻזָּתוֹ׃',
   'Vəʾim lōʾ-māṣəʾāh yādô dê hāšîv lô v''hāyāh mimkārô bəyad haqqōneh ʿad shənat hayyôvêl v''yāṣāʾ vayyôvêl v''shāv laʾăḥuzzātô.',
   'If neither a kinsman nor the individual himself could redeem the land, it would remain with the buyer "until the year of jubile." However, the ultimate safety net was the Jubilee itself: "and in the jubile it shall go out, and he shall return unto his possession." This highlights the Jubilee as the final and absolute mechanism for land reversion, ensuring that no family''s inheritance was permanently lost (Ezek 46:17).',
   'The Jubilee''s automatic release of land, even if unredeemed, underscores God''s unwavering commitment to justice and the preservation of family inheritances. It demonstrates a divine grace that provides a fresh start, preventing perpetual disadvantage and offering hope for restoration, mirroring God''s ultimate plan for cosmic renewal and the establishment of His eternal kingdom (Rom 8:21; Rev 21:5).'),
  (29,
   'And if a man sell a dwelling house in a walled city, then he may redeem it within a whole year after it is sold; within a full year may he redeem it.',
   'וְאִישׁ כִּי־יִמְכֹּר בֵּית מוֹשָׁב עִיר חוֹמָה וְהָיְתָה גְאֻלָּתוֹ עַד־תֹּם שְׁנַת מִמְכָּרוֹ יָמִים תִּהְיֶה גְאֻלָּתוֹ׃',
   'Vəʾîš kî-yimkōr bêt môshāv ʿîr ḥômāh v''hāyətāh gəʾullātô ʿad-tōm shənat mimkārô yāmîm tihyeh gəʾullātô.',
   'This verse introduces a special rule for "a dwelling house in a walled city." Unlike land, such a house could be redeemed only "within a whole year after it is sold." The limited redemption period reflects the different nature of urban property, which was not tied to ancestral agricultural inheritance. This distinction highlights the practicalities of urban life versus the agrarian foundation of Israelite society (Deut 3:5).',
   NULL),
  (30,
   'And if it be not redeemed within the space of a full year, then the house that is in the walled city shall be established for ever to him that bought it throughout his generations: it shall not go out in the jubile.',
   'וְאִם לֹא יִגָּאֵל עַד־מְלֹאת לוֹ שָׁנָה תְמִימָה וְקָם הַבַּיִת אֲשֶׁר בָּעִיר אֲשֶׁר־לוֹ חוֹמָה לַצְּמִיתֻת לַקֹּנֶה אֹתוֹ לְדֹרֹתָיו לֹא יֵצֵא בַּיֹּבֵל׃',
   'Vəʾim lōʾ yiggāʾēl ʿad-məlōʾt lô shānāh təmîmāh v''qām habbayit ʾăšer bāʿîr ʾăšer-lô ḥômāh laṣṣəmîtut laqqōneh ʾōtô lədorōtāyw lōʾ yēṣēʾ vayyôvêl.',
   'If a house in a walled city was not redeemed within the specified year, it became the permanent possession of the buyer and "shall not go out in the jubile." This exception to the Jubilee rule underscores the different legal status of urban property. Walled cities were often centers of commerce and administration, and their properties were not part of the original tribal land distribution, thus having a different redemption and reversion policy (Josh 14:4).',
   NULL),
  (31,
   'But the houses of the villages which have no wall round about them shall be counted as the fields of the country: they may be redeemed, and they shall go out in the jubile.',
   'וּבָתֵּי הַחֲצֵרִים אֲשֶׁר אֵין לָהֶם חוֹמָה סָבִיב עַל־שְׂדֵה הָאָרֶץ יֵחָשֵׁב הַגְּאֻלָּה תִּהְיֶה־לּוֹ וּבַיֹּבֵל יֵצֵא׃',
   'Uvattê haḥăṣērîm ʾăšer ʾên lāhem ḥômāh sāviv ʿal-śədēh hāʾāreṣ yēḥāshēv haggəʾullāh tihyeh-llô uvayyôvêl yēṣēʾ.',
   'In contrast to houses in walled cities, "the houses of the villages which have no wall round about them shall be counted as the fields of the country." This meant they were subject to the same redemption laws as agricultural land, including the automatic reversion in the Jubilee year. This distinction highlights the importance of the wall as a defining feature for property law, separating urban centers from rural settlements (Deut 3:5).',
   NULL),
  (32,
   'Notwithstanding the cities of the Levites, and the houses of the cities of their possession, may the Levites redeem at any time.',
   'וְעָרֵי הַלְוִיִּם בָּתֵּי עָרֵי אֲחֻזָּתָם גְּאֻלַּת עוֹלָם תִּהְיֶה לַלְוִיִּם׃',
   'Vəʿārê halwiyyim battê ʿārê ʾăḥuzzātām gəʾullat ʿôlām tihyeh lalləwiyyim.',
   'This verse introduces a special provision for the Levites. "The cities of the Levites, and the houses of the cities of their possession, may the Levites redeem at any time." Unlike other Israelites, Levites did not receive a tribal land inheritance but were allotted cities and their surrounding pasturelands (Num 35:1-8). This perpetual redemption right ensured their ability to maintain their designated dwelling places, essential for their priestly service (Josh 21:1-42).',
   NULL),
  (33,
   'And if a man purchase of the Levites, then the house that was sold, and the city of his possession, shall go out in the year of jubile: for the houses of the cities of the Levites are their possession among the children of Israel.',
   'וְאִישׁ מִן־הַלְוִיִּם כִּי יִגְאַל וְיָצָא מִמְכַּר־בַּיִת וְעִיר אֲחֻזָּתוֹ בַּיֹּבֵל כִּי בָתֵּי עָרֵי הַלְוִיִּם הִוא אֲחֻזָּתָם בְּתוֹךְ בְּנֵי יִשְׂרָאֵל׃',
   'Vəʾîš min-halləwiyyim kî yigʾal v''yāṣāʾ mimkar-bayit v''ʿîr ʾăḥuzzātô bayyôvêl kî battê ʿārê halləwiyyim hîʾ ʾăḥuzzātām bətôḵ bənê Yiśrāʾēl.',
   'This verse clarifies that if a Levite sold a house, it would still "go out in the year of jubile" if not redeemed, similar to village houses. However, the unique aspect for Levites is their perpetual right to redeem (Lev 25:32). This ensures that their designated cities, which were their "possession among the children of Israel," remained available for their use, preventing their displacement and ensuring their ability to fulfill their sacred duties (Num 35:2).',
   NULL),
  (34,
   'But the field of the suburbs of their cities may not be sold; for it is their perpetual possession.',
   'וּשְׂדֵה מִגְרַשׁ עָרֵיהֶם לֹא יִמָּכֵר כִּי־חֻקַּת עוֹלָם הוּא לָהֶם׃',
   'Usdəh migrash ʿārêhem lōʾ yimmāḵēr kî-ḥuqqat ʿôlām hûʾ lāhem.',
   'The "field of the suburbs of their cities" (שְׂדֵה מִגְרַשׁ עָרֵיהֶם), which were the pasturelands surrounding the Levite cities, "may not be sold" at all. This was considered their "perpetual possession" (חֻקַּת עוֹלָם). These lands were vital for their livestock and sustenance, and their inalienability ensured the Levites'' economic stability and ability to perform their service without being dispossessed (Num 35:3).',
   NULL),
  (35,
   'And if thy brother be waxen poor, and fallen in decay with thee; then thou shalt relieve him: yea, though he be a stranger, or a sojourner; that he may live with thee.',
   'וְכִי־יָמוּךְ אָחִיךָ וּמָטָה יָדוֹ עִמָּךְ וְהֶחֱזַקְתָּ בּוֹ גֵּר וְתוֹשָׁב וָחַי עִמָּךְ׃',
   'Vəḵî-yāmûḵ ʾāḥîḵā ûmāṭāh yādô ʿimmāḵ v''heḥĕzaqtā bô gēr v''tôshāv vāḥay ʿimmāḵ.',
   'This verse shifts to laws concerning poverty and assistance. If a "brother be waxen poor, and fallen in decay with thee," the command is to "relieve him" (וְהֶחֱזַקְתָּ בּוֹ). This duty extends even to "a stranger, or a sojourner" (גֵּר וְתוֹשָׁב), ensuring they "may live with thee." This highlights a strong ethic of communal responsibility and hospitality, especially towards the vulnerable, reflecting God''s compassion (Deut 15:7-8; Ps 41:1).',
   'This command to "relieve" the poor, including strangers and sojourners, is a powerful expression of God''s heart for the vulnerable and marginalized. It establishes a moral imperative for communal care and hospitality, reflecting the divine attribute of compassion. This principle is foundational to Christian charity and social justice, calling believers to actively support those in need (Matt 25:35-40; Jas 2:15-16).'),
  (36,
   'Take thou no usury of him, or increase: but fear thy God; that thy brother may live with thee.',
   'אַל־תִּקַּח מֵאִתּוֹ נֶשֶׁךְ וְתַרְבִּית וְיָרֵאתָ מֵאֱלֹהֶיךָ וְחֵי אָחִיךָ עִמָּךְ׃',
   'ʾAl-tiqqaḥ mêʾittô nesheḵ v''tarbît v''yārēʾtā mêʾĕlōheyḵā v''ḥê ʾāḥîḵā ʿimmāḵ.',
   'This verse prohibits taking "usury" (נֶשֶׁךְ, neshekh) or "increase" (תַּרְבִּית, tarbit) from a poor brother. "Neshekh" refers to interest on money, while "tarbit" refers to interest on food or goods. The motivation is again "but fear thy God" (וְיָרֵאתָ מֵאֱלֹהֶיךָ), ensuring that the impoverished brother "may live with thee." This law protected the poor from falling into deeper debt and exploitation, promoting economic justice (Exod 22:25; Deut 23:19-20).',
   'The prohibition against usury for a needy brother reveals God''s ethical standard for economic transactions within the covenant community. It underscores that financial dealings should be driven by compassion and the desire for a brother''s survival, not by profit maximization at the expense of the vulnerable. This principle reflects God''s character as a just and merciful provider, calling His people to imitate His benevolence (Luke 6:34-35).'),
  (37,
   'Thou shalt not give him thy money upon usury, nor lend him thy victuals for increase.',
   'אֶת־כַּסְפְּךָ לֹא־תִתֵּן לוֹ בְּנֶשֶׁךְ וּבְמַרְבִּית לֹא־תִתֵּן אָכְלְךָ׃',
   'Et-kaspeḵā lōʾ-tittēn lô bənesheḵ uvmarbît lōʾ-tittēn ʾoḵləḵā.',
   'This verse reiterates the prohibition against usury, specifically mentioning "thy money upon usury" (כַּסְפְּךָ לֹא־תִתֵּן לוֹ בְּנֶשֶׁךְ) and "thy victuals for increase" (וּבְמַרְבִּית לֹא־תִתֵּן אָכְלְךָ). This detailed instruction ensures that the command is understood broadly, covering both monetary and in-kind loans. The aim is to provide genuine assistance to the poor without burdening them further (Neh 5:7-11).',
   NULL),
  (38,
   'I am the LORD your God, which brought you forth out of the land of Egypt, to give you the land of Canaan, and to be your God.',
   'אֲנִי יְהוָה אֱלֹהֵיכֶם אֲשֶׁר הוֹצֵאתִי אֶתְכֶם מֵאֶרֶץ מִצְרַיִם לָתֵת לָכֶם אֶת־אֶרֶץ כְּנַעַן לִהְיוֹת לָכֶם לֵאלֹהִים׃',
   'ʾĂnî YHWH ʾĕlōhêkem ʾăšer hôṣēʾtî etḵem mêʾereṣ Miṣrayim lātēt lākem et-ʾereṣ Kənaʿan lihyôt lākem lēʾlōhîm.',
   'This verse provides the ultimate theological basis for all these laws: "I am the LORD your God, which brought you forth out of the land of Egypt, to give you the land of Canaan, and to be your God." This reminder of the Exodus and the covenant relationship underscores God''s authority and His redemptive acts. Their liberation from slavery in Egypt obligates them to practice justice and mercy, especially towards the poor, reflecting God''s character (Exod 20:2; Deut 5:6).',
   'This powerful declaration grounds all ethical and social laws in God''s redemptive history with Israel. The Exodus deliverance and the gift of Canaan are not just historical events but foundational to Israel''s identity and moral obligations. It teaches that God''s grace demands a response of obedience and a life that reflects His justice and mercy, establishing a pattern for Christian living in light of Christ''s redemption (Rom 12:1-2; 1 Pet 1:15-16).'),
  (39,
   'And if thy brother that dwelleth by thee be waxen poor, and be sold unto thee; thou shalt not compel him to serve as a bondservant:',
   'וְכִי־יָמוּךְ אָחִיךָ עִמָּךְ וְנִמְכַּר־לָךְ לֹא־תַעֲבֹד בּוֹ עֲבֹדַת עָבֶד׃',
   'Vəḵî-yāmûḵ ʾāḥîḵā ʿimmāḵ v''nimkar-lāḵ lōʾ-taʿăvōd bô ʿăvōdat ʿāved.',
   'This verse addresses the situation where an Israelite brother, due to extreme poverty, "be sold unto thee." The crucial command is "thou shalt not compel him to serve as a bondservant" (לֹא־תַעֲבֹד בּוֹ עֲבֹדַת עָבֶד). This distinguishes the treatment of an Israelite who sells himself into servitude from that of a foreign slave, emphasizing the unique status of God''s people as His servants (Exod 21:2-6).',
   'This law highlights the sanctity of an Israelite''s personhood and freedom, even in economic distress. It reflects God''s abhorrence of perpetual slavery for His covenant people, who were themselves redeemed from Egyptian bondage. This principle foreshadows the spiritual freedom and dignity that believers find in Christ, who liberates them from the bondage of sin (John 8:36; Gal 5:1).'),
  (40,
   'But as an hired servant, and as a sojourner, he shall be with thee, and shall serve thee unto the year of jubile:',
   'כְּשָׂכִיר כְּתוֹשָׁב יִהְיֶה עִמָּךְ עַד־שְׁנַת הַיּוֹבֵל יַעֲבֹד עִמָּךְ׃',
   'Kəśāḵîr kətôshāv yihyeh ʿimmāḵ ʿad-shənat hayyôvêl yaʿăvōd ʿimmāḵ.',
   'Instead of a bondservant, an impoverished Israelite was to be treated "as an hired servant, and as a sojourner." His service was limited "unto the year of jubile." This temporary and dignified form of service ensured that he retained his status as a free Israelite, with the ultimate prospect of full liberation and restoration of his family and land at the Jubilee (Deut 15:12-18).',
   NULL),
  (41,
   'And then shall he depart from thee, both he and his children with him, and shall return unto his own family, and unto the possession of his fathers shall he return.',
   'וְיָצָא מֵעִמָּךְ הוּא וּבָנָיו עִמּוֹ וְשָׁב אֶל־מִשְׁפַּחְתּוֹ וְאֶל־אֲחֻזַּת אֲבֹתָיו יָשׁוּב׃',
   'Vəyāṣāʾ mēʿimmāḵ hûʾ ûvānāyw ʿimmô v''shāv el-mišpaḥtô v''el-ʾăḥuzzat ʾăvōtāyw yāshûv.',
   'At the Jubilee, the Israelite servant and "his children with him" were to "depart from thee" and "return unto his own family, and unto the possession of his fathers shall he return." This comprehensive release ensured the restoration of family unity and the re-establishment of the family''s economic base, preventing the creation of a permanent underclass within Israel (Exod 21:3-4).',
   NULL),
  (42,
   'For they are my servants, which I brought forth out of the land of Egypt: they shall not be sold as bondmen.',
   'כִּי עֲבָדַי הֵם אֲשֶׁר־הוֹצֵאתִי אֹתָם מֵאֶרֶץ מִצְרָיִם לֹא יִמָּכְרוּ מִמְכֶּרֶת עָבֶד׃',
   'Kî ʿăvādāy hēm ʾăšer-hôṣēʾtî ʾōtām mêʾereṣ Miṣrayim lōʾ yimmāḵrû mimkeret ʿāved.',
   'This verse provides the theological rationale for the special treatment of Israelite servants: "For they are my servants, which I brought forth out of the land of Egypt: they shall not be sold as bondmen." Their redemption from Egyptian slavery by God Himself established their unique status as God''s property, not human property. This divine ownership precluded their permanent enslavement by fellow Israelites (Exod 19:5-6).',
   'This declaration, "For they are my servants," is a profound theological statement of God''s ownership and covenant relationship with Israel. Having been redeemed from slavery by God, they could not be permanently enslaved by others. This principle underscores the spiritual freedom and dignity of those whom God has redeemed, foreshadowing the ultimate liberation from sin and death achieved by Christ, making believers servants of God alone (1 Cor 7:23; Rom 6:22).'),
  (43,
   'Thou shalt not rule over him with rigour; but shalt fear thy God.',
   'לֹא־תִרְדֶּה בוֹ בְּפָרֶךְ וְיָרֵאתָ מֵאֱלֹהֶיךָ׃',
   'Lōʾ-tirddeh bô bəfāreḵ v''yārēʾtā mêʾĕlōheyḵā.',
   'The command "Thou shalt not rule over him with rigour" (לֹא־תִרְדֶּה בוֹ בְּפָרֶךְ) explicitly prohibits harsh or oppressive treatment of an Israelite servant. The motivation, once again, is "but shalt fear thy God." This reinforces the idea that ethical treatment of others is a direct expression of one''s reverence for God and adherence to His covenant principles (Eph 6:9; Col 4:1).',
   'The prohibition against ruling "with rigour" (בְּפָרֶךְ) over an Israelite servant, coupled with the command to "fear thy God," emphasizes the inherent dignity of every individual created in God''s image and redeemed by Him. This principle extends beyond legal requirements, calling for compassionate and humane treatment, reflecting God''s own character of mercy and justice (Col 4:1; Eph 6:9).'),
  (44,
   'Both thy bondmen, and thy bondmaids, which thou shalt have, shall be of the heathen that are round about you; of them shall ye buy bondmen and bondmaids.',
   'וְעַבְדְּךָ וַאֲמָתְךָ אֲשֶׁר יִהְיוּ־לָךְ מֵאֵת הַגּוֹיִם אֲשֶׁר סְבִיבֹתֵיכֶם מֵהֶם תִּקְנוּ עֶבֶד וְאָמָה׃',
   'Vəʿavdəḵā vaʾămātəḵā ʾăšer yihyû-lāḵ mêʾēt haggôyim ʾăšer səvîvōtêḵem mēhem tiqnû ʿeved v''ʾāmāh.',
   'This verse distinguishes between Israelite and foreign servitude. "Both thy bondmen, and thy bondmaids, which thou shalt have, shall be of the heathen that are round about you; of them shall ye buy bondmen and bondmaids." This permission to acquire foreign slaves reflects the ancient Near Eastern context but is carefully regulated within Israel. These foreign slaves were not under the same Jubilee release provisions as Israelites (Deut 20:10-14).',
   NULL),
  (45,
   'Moreover of the children of the strangers that do sojourn among you, of them shall ye buy, and of their families that are with you, which they begat in your land: and they shall be your possession.',
   'וְגַם מִבְּנֵי הַתּוֹשָׁבִים הַגָּרִים עִמָּכֶם מֵהֶם תִּקְנוּ וּמִמִּשְׁפְּחֹתָם אֲשֶׁר עִמָּכֶם אֲשֶׁר הוֹלִידוּ בְּאַרְצְכֶם וְהָיוּ לָכֶם לַאֲחֻזָּה׃',
   'Vəgam mibbənê hattôshāvîm haggārîm ʿimmāḵem mēhem tiqnû ûmimmishpəḥōtām ʾăšer ʿimmāḵem ʾăšer hôlîdû bəʾarṣəḵem v''hāyû lāḵem laʾăḥuzzāh.',
   'In addition to foreign nations, Israelites could also acquire slaves "of the children of the strangers that do sojourn among you... which they begat in your land." These individuals, though living in Israel, were not part of the covenant community and thus fell under the category of foreign slaves. They "shall be your possession," indicating a permanent form of servitude (Exod 12:48-49).',
   NULL),
  (46,
   'And ye shall take them as an inheritance for your children after you, to inherit them for a possession; they shall be your bondmen for ever: but over your brethren the children of Israel, ye shall not rule one over another with rigour.',
   'וְהִתְנַחַלְתֶּם אֹתָם לִבְנֵיכֶם אַחֲרֵיכֶם לָרֶשֶׁת אֲחֻזָּה לְעוֹלָם בָּהֶם תַּעֲבֹדוּ וּבְאַחֵיכֶם בְּנֵי יִשְׂרָאֵל אִישׁ בְּאָחִיו לֹא־תִרְדֶּה בוֹ בְּפָרֶךְ׃',
   'Vəhitnaḥaltem ʾōtām livnêḵem ʾaḥărêḵem lārešet ʾăḥuzzāh ləʿôlām bāhem taʿăvōdû uvʾaḥêḵem bənê Yiśrāʾēl ʾîš bəʾāḥîv lōʾ-tirddeh bô bəfāreḵ.',
   'Foreign slaves could be taken "as an inheritance for your children after you, to inherit them for a possession; they shall be your bondmen for ever." This contrasts sharply with Israelite servants. The verse concludes by reiterating the core distinction: "but over your brethren the children of Israel, ye shall not rule one over another with rigour." This highlights the unique covenant status of Israelites (Isa 14:2).',
   'This verse starkly contrasts the treatment of foreign slaves with that of Israelite servants, emphasizing the unique covenant relationship God had with His chosen people. While the allowance of foreign slavery reflects the cultural norms of the ancient world, the strict prohibition against permanent enslavement and harsh rule over fellow Israelites underscores the value God places on the freedom and dignity of His redeemed. This distinction points to the spiritual reality that those in Christ are free, while those outside remain in bondage (Gal 3:28; Col 3:11).'),
  (47,
   'And if a sojourner or stranger wax rich by thee, and thy brother that dwelleth by him wax poor, and sell himself unto the stranger or sojourner by thee, or to the stock of the stranger’s family:',
   'וְכִי תַשִּׂיג יַד־גֵּר וְתוֹשָׁב עִמָּךְ וּמָךְ אָחִיךָ עִמּוֹ וְנִמְכַּר לְגֵר תּוֹשָׁב עִמָּךְ אוֹ לְעֵקֶר מִשְׁפַּחַת גֵּר׃',
   'Vəḵî tassîg yad-gēr v''tôshāv ʿimmāḵ ûmāḵ ʾāḥîḵā ʿimmô v''nimkar ləgēr tôshāv ʿimmāḵ ʾô ləʿēqer mishpaḥat gēr.',
   'This verse addresses a particularly sensitive situation: an Israelite becoming so poor that he "sell himself unto the stranger or sojourner by thee, or to the stock of the stranger’s family." This scenario was considered a great indignity, as it meant an Israelite, God''s servant, was serving a non-Israelite. The subsequent verses outline the redemption process for such an individual, emphasizing the importance of their freedom (Neh 5:5).',
   NULL),
  (48,
   'After that he is sold he may be redeemed again; one of his brethren may redeem him:',
   'אַחֲרֵי נִמְכַּר גְּאֻלָּה תִּהְיֶה־לּוֹ אֶחָד מֵאֶחָיו יִגְאָלֶנּוּ׃',
   'ʾAḥărê nimkar gəʾullāh tihyeh-llô ʾeḥad mêʾeḥāyw yigʾālennû.',
   'Despite the shame of an Israelite selling himself to a foreigner, the law immediately provides for his redemption: "After that he is sold he may be redeemed again; one of his brethren may redeem him." This underscores the high value placed on the freedom of an Israelite, even when they had fallen into such a dire state. The kinsman-redeemer (goel) again plays a vital role (Ruth 4:4).',
   NULL),
  (49,
   'Either his uncle, or his uncle’s son, may redeem him, or any that is nigh of kin unto him of his family may redeem him; or if he be able, he may redeem himself.',
   'אוֹ דֹדוֹ אוֹ בֶן־דֹּדוֹ יִגְאָלֶנּוּ אוֹ מִשְּׁאֵר בְּשָׂרוֹ מִמִּשְׁפַּחְתּוֹ יִגְאָלֶנּוּ אוֹ הִשִּׂיגָה יָדוֹ וְנִגְאָל׃',
   'ʾÔ dôdô ʾô ven-dôdô yigʾālennû ʾô mishshəʾēr bəśārô mimmishpaḥtô yigʾālennû ʾô hissîgāh yādô v''nigʾāl.',
   'This verse expands on who could act as a kinsman-redeemer: "Either his uncle, or his uncle’s son, may redeem him, or any that is nigh of kin unto him of his family may redeem him." Furthermore, if the individual himself "be able, he may redeem himself." This broad provision for redemption highlights the communal responsibility to restore a fellow Israelite to freedom and dignity (Jer 32:8).',
   NULL),
  (50,
   'And he shall reckon with him that bought him from the year that he was sold to him unto the year of jubile: and the price of his sale shall be according unto the number of years, according to the time of an hired servant shall it be with him.',
   'וְחִשַּׁב עִם־קֹנֵהוּ מִשְּׁנַת הִמָּכְרוֹ לוֹ עַד שְׁנַת הַיּוֹבֵל וְהָיָה כֶּסֶף מִמְכָּרוֹ בְּמִסְפַּר שָׁנִים כִּימֵי שָׂכִיר יִהְיֶה עִמּוֹ׃',
   'Vəḥiššav ʿim-qōnēhû mishshənat himmāḵrô lô ʿad shənat hayyôvêl v''hāyāh kesef mimkārô bəmispar shānîm kîmê śāḵîr yihyeh ʿimmô.',
   'The redemption price was calculated based on the remaining years until the Jubilee. The redeemer would "reckon with him that bought him from the year that he was sold to him unto the year of jubile." The price was determined "according unto the number of years, according to the time of an hired servant." This means the buyer was compensated for the lost labor, not the full "purchase" price, as the Israelite was never truly a permanent slave (Lev 25:15-16).',
   NULL),
  (51,
   'If there be yet many years behind, according unto them he shall give again the price of his redemption out of the money that he was bought for.',
   'אִם־עוֹד רַבּוֹת שָׁנִים בָּהּ לְפִיהֶן יָשִׁיב גְּאֻלָּתוֹ מִכֶּסֶף מִקְנָתוֹ׃',
   'ʾIm-ʿôd rabbôt shānîm bāh ləfîhen yāshîv gəʾullātô mikkesef miqnātô.',
   'If "many years" remained until the Jubilee, the redemption price would be higher, proportional to the remaining service. The redeemer would "give again the price of his redemption out of the money that he was bought for." This further clarifies the pro-rata calculation, ensuring fairness to both the foreign master and the Israelite being redeemed (Lev 25:16).',
   NULL),
  (52,
   'And if there remain but few years unto the year of jubile, then he shall count with him, and according unto his years shall he give him again the price of his redemption.',
   'וְאִם־מְעַט נִשְׁאַר בַּשָּׁנִים עַד־שְׁנַת הַיּוֹבֵל וְחִשַּׁב־לוֹ כְּפִי שָׁנָיו יָשִׁיב אֶת־גְּאֻלָּתוֹ׃',
   'Vəʾim-məʿaṭ nishʾar baššānîm ʿad-shənat hayyôvêl v''ḥishshav-lô kəfî shānāyw yāshîv et-gəʾullātô.',
   'Conversely, "if there remain but few years unto the year of jubile, then he shall count with him, and according unto his years shall he give him again the price of his redemption." This reiterates the proportional pricing, ensuring that the redemption cost accurately reflected the remaining period of service, whether long or short (Lev 25:16).',
   NULL),
  (53,
   'And as a yearly hired servant shall he be with him: and the other shall not rule with rigour over him in thy sight.',
   'כִּשְׂכִיר שָׁנָה בְּשָׁנָה יִהְיֶה עִמּוֹ לֹא־יִרְדֶּנּוּ בְּפֶרֶךְ לְעֵינֶיךָ׃',
   'Kisḵîr shānāh bəshānāh yihyeh ʿimmô lōʾ-yirdennû bəfereḵ ləʿêneyḵā.',
   'Even while serving a foreign master, the Israelite was to be treated "as a yearly hired servant" (כִּשְׂכִיר שָׁנָה בְּשָׁנָה). The foreign master was explicitly commanded "not rule with rigour over him in thy sight." This implies that the Israelite community had a responsibility to ensure their brethren were not oppressed, even by foreign masters, upholding the dignity of God''s people (Exod 1:13-14).',
   NULL),
  (54,
   'And if he be not redeemed in these years, then he shall go out in the year of jubile, both he, and his children with him.',
   'וְאִם־לֹא יִגָּאֵל בְּאֵלֶּה וְיָצָא בִּשְׁנַת הַיּוֹבֵל הוּא וּבָנָיו עִמּוֹ׃',
   'Vəʾim-lōʾ yiggāʾēl bəʾēlleh v''yāṣāʾ bishnat hayyôvêl hûʾ ûvānāyw ʿimmô.',
   'As with land, if an Israelite sold into foreign servitude was not redeemed by a kinsman or himself, the Jubilee provided the ultimate release: "then he shall go out in the year of jubile, both he, and his children with him." This final provision underscores the absolute and non-negotiable freedom of God''s people, guaranteed by divine law, regardless of their circumstances (Isa 61:1-2).',
   NULL),
  (55,
   'For unto me the children of Israel are servants; they are my servants whom I brought forth out of the land of Egypt: I am the LORD your God.',
   'כִּי־לִי בְנֵי יִשְׂרָאֵל עֲבָדִים עֲבָדַי הֵם אֲשֶׁר הוֹצֵאתִי אֹתָם מֵאֶרֶץ מִצְרַיִם אֲנִי יְהוָה אֱלֹהֵיכֶם׃',
   'Kî-lî bənê Yiśrāʾēl ʿăvādîm ʿăvādāy hēm ʾăšer hôṣēʾtî ʾōtām mêʾereṣ Miṣrayim ʾănî YHWH ʾĕlōhêkem.',
   'This verse concludes the chapter with a powerful reaffirmation of God''s ownership over Israel: "For unto me the children of Israel are servants; they are my servants whom I brought forth out of the land of Egypt: I am the LORD your God." This reiterates the theological foundation for all the laws concerning land and servitude, emphasizing that Israel''s identity and freedom are rooted in their covenant relationship with God, who redeemed them from bondage (Rom 6:22; 1 Cor 7:23).',
   'This concluding declaration powerfully reiterates the core theological truth that Israel belongs to God as His redeemed servants. Their liberation from Egypt established an unbreakable bond, making them accountable to Him alone. This principle extends to all believers in Christ, who are bought with a price and are therefore servants of God, called to live in freedom from sin and human bondage, reflecting His glory (1 Cor 6:19-20; Gal 5:13).')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Leviticus' AND c.chapter_number = 25;

-- Step 3: Word Studies for key verses

-- Verse 2
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, ws.original_word, ws.transliteration, ws.strongs_number, ws.meaning, ws.word_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  ('שַׁבָּת', 'Shabbat', 'H7676', 'From H7673, meaning "to cease, desist, rest." "Shabbat" refers to the Sabbath, a day or period of rest. Theologically, it signifies a divinely ordained cessation from labor, reflecting God''s rest after creation (Gen 2:2-3). For the land, it emphasizes God''s ownership and the need for ecological and spiritual renewal, fostering trust in His provision.', 1),
  ('לַיהוָה', 'laYHWH', 'H3068', 'The prefix "la-" means "to" or "for." YHWH (Yahweh) is the sacred personal name of God, often translated "the LORD." It signifies God''s self-existence, covenant faithfulness, and active presence. Designating the Sabbath "for the LORD" underscores its sacred purpose and ultimate dedication to Him as the sovereign Creator and Redeemer.', 2),
  ('הָאָרֶץ', 'ha''aretz', 'H776', 'The definite article "ha-" means "the." "Eretz" means "land, earth, ground." It refers to the physical territory, specifically the promised land of Canaan. Theologically, it represents God''s creation and the specific inheritance given to Israel, emphasizing that even the physical earth is subject to God''s laws and has a sacred dimension.', 3)
) AS ws(original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Leviticus' AND c.chapter_number = 25 AND v.verse_number = 2;

-- Verse 10
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, ws.original_word, ws.transliteration, ws.strongs_number, ws.meaning, ws.word_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  ('יוֹבֵל', 'Yovel', 'H3104', 'Derived from a root meaning "to flow, stream," but commonly associated with the "ram''s horn" (yobel) blown to announce the year. Theologically, the Jubilee is a year of ultimate liberation and restoration, symbolizing God''s radical justice, equity, and the cyclical renewal of His covenant with Israel, preventing permanent social stratification.', 1),
  ('דְּרוֹר', 'Dror', 'H1865', 'Meaning "freedom, liberty, release." This term is used specifically for the proclamation of freedom in the Jubilee. Theologically, it signifies a comprehensive liberation from economic bondage and social oppression, reflecting God''s character as a liberator and foreshadowing the ultimate spiritual freedom found in Christ (Isa 61:1).', 2),
  ('אֲחֻזָּתוֹ', 'Achuzzato', 'H272', 'From H270, meaning "to grasp, take possession." "Achuzzah" refers to a "possession, inheritance, property," specifically the ancestral land allotted to each Israelite family. Theologically, its return in the Jubilee emphasizes the sanctity of family inheritance and God''s design for stable, equitable distribution of resources among His people.', 3),
  ('מִשְׁפַּחְתּוֹ', 'Mishpaḥtô', 'H4940', 'From H8199, meaning "to spread out." "Mishpaḥah" means "family, clan, tribe." The return to one''s family in the Jubilee highlights the importance of kinship and communal identity in Israelite society. Theologically, it signifies the restoration of social bonds and the prevention of permanent alienation, reflecting God''s concern for family integrity.', 4)
) AS ws(original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Leviticus' AND c.chapter_number = 25 AND v.verse_number = 10;

-- Verse 17
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, ws.original_word, ws.transliteration, ws.strongs_number, ws.meaning, ws.word_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  ('תוֹנוּ', 'Tonu', 'H3238', 'From the root ינה (yanah), meaning "to oppress, wrong, defraud, deal violently." The negative command "lo tonu" means "you shall not oppress." Theologically, this prohibition underscores God''s demand for justice and ethical conduct in all human interactions, particularly in economic dealings, reflecting His own righteous character and concern for the vulnerable.', 1),
  ('יְהוָה', 'YHWH', 'H3068', 'The sacred personal name of God, often translated "the LORD." It signifies God''s self-existence, covenant faithfulness, and active presence. In this context, it serves as the ultimate authority and guarantor of the laws, reminding Israel that their ethical conduct is a direct response to their relationship with their sovereign God.', 2),
  ('אֱלֹהֵיכֶם', 'Eloheykem', 'H430', 'From H410, meaning "God, gods." The suffix "-khem" means "your." "Elohim" is a plural noun used for the singular God, emphasizing His majesty and power. The phrase "your God" highlights the covenant relationship, reminding Israel that their obedience is owed to the mighty God who chose them and established His laws for their well-being.', 3)
) AS ws(original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Leviticus' AND c.chapter_number = 25 AND v.verse_number = 17;

-- Verse 23
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, ws.original_word, ws.transliteration, ws.strongs_number, ws.meaning, ws.word_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  ('לִצְמִתֻת', 'Litzmitut', 'H6783', 'From H6782, meaning "to cut off, destroy." "Tzmitut" means "permanently, for ever, irrevocably." The phrase "lo timmāḵēr liṣmitut" means "it shall not be sold permanently." Theologically, this emphasizes God''s ultimate ownership of the land, preventing its permanent alienation and ensuring that human tenure is always temporary and conditional upon His sovereign will.', 1),
  ('גֵּרִים', 'Gerim', 'H1616', 'Plural of גֵּר (ger), meaning "sojourner, stranger, alien." These were non-Israelites residing in the land, often without full rights. Theologically, Israel''s identification as "gerim" with God reminds them of their dependent status and temporary earthly dwelling, fostering humility and empathy for actual strangers, and pointing to a heavenly citizenship.', 2),
  ('תּוֹשָׁבִים', 'Toshvim', 'H8453', 'Plural of תּוֹשָׁב (toshāv), meaning "sojourner, temporary resident." Similar to "ger," but sometimes implying a more settled, though still non-permanent, resident. Theologically, this term reinforces the idea that Israel''s possession of the land is a stewardship, not absolute ownership, and that their ultimate home and security are found in God alone.', 3)
) AS ws(original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Leviticus' AND c.chapter_number = 25 AND v.verse_number = 23;

-- Verse 25
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, ws.original_word, ws.transliteration, ws.strongs_number, ws.meaning, ws.word_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  ('יָמוּךְ', 'Yamukh', 'H4134', 'From the root מוך (muk), meaning "to be low, be impoverished, become poor." It describes the state of an Israelite brother falling into poverty. Theologically, this condition triggers the divine laws of redemption, highlighting God''s concern for the economically vulnerable and His provision of mechanisms to prevent permanent destitution among His people.', 1),
  ('גֹאֲלוֹ', 'Go''alo', 'H1350', 'From the root גאל (ga''al), meaning "to redeem, act as kinsman." "Goel" refers to a "kinsman-redeemer," one who has the right and obligation to redeem a relative''s person or property. Theologically, the goel embodies the principle of redemptive love and justice within the family, foreshadowing Christ''s role as the ultimate Kinsman-Redeemer for humanity.', 2),
  ('וְגָאַל', 'V''ga''al', 'H1350', 'The verb form of the root גאל (ga''al), meaning "he shall redeem." This action signifies the practical outworking of the goel''s responsibility. Theologically, it represents the act of restoration and liberation from bondage or loss, demonstrating God''s active intervention through human agents to uphold justice and preserve covenant relationships.', 3)
) AS ws(original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Leviticus' AND c.chapter_number = 25 AND v.verse_number = 25;

-- Verse 42
INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, ws.original_word, ws.transliteration, ws.strongs_number, ws.meaning, ws.word_order
FROM verses v
JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  ('עֲבָדַי', 'Avaday', 'H5650', 'Plural of עֶבֶד (eved), meaning "servant, slave." The suffix "-ay" means "my." "My servants" refers to the children of Israel. Theologically, this declaration asserts God''s exclusive ownership over Israel, based on their redemption from Egypt. It means they are bound to serve Him alone, not human masters permanently, establishing their unique dignity and freedom.', 1),
  ('הוֹצֵאתִי', 'Hotseti', 'H3318', 'From the root יצא (yatsa), meaning "to go out, come forth." In the Hiphil stem, it means "I brought out, caused to come forth." This refers to God''s act of leading Israel out of Egypt. Theologically, the Exodus is the foundational redemptive event, establishing God''s power, faithfulness, and His right to claim Israel as His own, setting the precedent for their freedom.', 2),
  ('מִצְרַיִם', 'Mitzrayim', 'H4714', 'The Hebrew name for "Egypt." The land from which Israel was delivered. Theologically, Egypt represents a place of bondage, oppression, and idolatry. God''s act of bringing Israel out of Mitzrayim is the ultimate demonstration of His liberating power and His commitment to His covenant people, setting them apart for His service.', 3)
) AS ws(original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Leviticus' AND c.chapter_number = 25 AND v.verse_number = 42;

